                /*
                 * Get password as a passin argument: First split option name
                 * and passphrase argument into two strings
                 */
                *passin = 0;
                passin++;
                if (app_passwd(passin, NULL, &passwd, NULL) == 0) {
                    BIO_printf(bio_err, "failed to get '%s'\n", opt);
                    goto end;
